import java.util.*;
public class App {
    static int[] callCount = {0};
    static String compute() { callCount[0]++; return "computed"; }

    public static void main(String[] args) {
        Optional<String> present = Optional.of("value");
        Optional<String> absent  = Optional.empty();

        // orElse — ALWAYS calls compute()
        callCount[0] = 0;
        present.orElse(compute());  // compute() called even though present!
        absent.orElse(compute());
        System.out.println("orElse calls: present=1 absent=1");

        // orElseGet — LAZY: only calls when empty
        callCount[0] = 0;
        present.orElseGet(() -> compute());  // NOT called
        absent.orElseGet(() -> compute());   // called
        System.out.println("orElseGet calls: present=0 absent=1");
    }
}

import java.util.*;
class Product {
    String id, name; double price;
    Product(String i, String n, double p) { id=i; name=n; price=p; }
}
public class App {
    static Optional<Product> findProductById(List<Product> catalog, String id) {
        return catalog.stream()
            .filter(p -> p.id.equals(id))
            .findFirst();
    }

    public static void main(String[] args) {
        List<Product> catalog = Arrays.asList(
            new Product("P01", "Mouse",    799),
            new Product("P02", "Keyboard", 1999)
        );

        String id1 = "P01", id2 = "X99";

        findProductById(catalog, id1)
            .ifPresentOrElse(
                p -> System.out.println("Found: " + p.name + " ₹" + p.price),
                () -> System.out.println("Not found: No product with ID '" + id1 + "'")
            );

        findProductById(catalog, id2)
            .ifPresentOrElse(
                p -> System.out.println("Found: " + p.name + " ₹" + p.price),
                () -> System.out.println("Not found: No product with ID '" + id2 + "'")
            );
    }
}

