import java.util.*;
class CEO {
    String name;
    Optional<String> bio;
    CEO(String n, String b) { name=n; bio=Optional.ofNullable(b); }
    Optional<String> getBio() { return bio; }
}
class Company {
    String name;
    Optional<CEO> ceo;
    Company(String n, CEO c) { name=n; ceo=Optional.ofNullable(c); }
    Optional<CEO> getCeo() { return ceo; }
}
public class App {
    static String getCeoBio(Company company) {
        return company.getCeo()
            .flatMap(CEO::getBio)  // flatMap because getBio() returns Optional
            .orElse(company.getCeo().isPresent() ? "No bio written" : "Position vacant");
    }

    public static void main(String[] args) {
        Company tcs     = new Company("TCS",     new CEO("Rajesh", "Technology leader"));
        Company startup = new Company("Startup", null);  // no CEO
        Company meta    = new Company("Meta",    new CEO("Mark",   null));  // CEO, no bio

        System.out.println("TCS CEO bio: \"" + getCeoBio(tcs) + "\"");
        System.out.println("Startup CEO bio: " + getCeoBio(startup));
        System.out.println("Meta CEO bio: " + getCeoBio(meta));
    }
}

