    static Product findMostExpensiveInStock(List<Product> catalog) {
        return catalog.stream()
            .filter(p -> p.inStock)
            .max(Comparator.comparingDouble(p -> p.price))
            .orElseThrow(() -> new ProductNotFoundException("No in-stock products found"));
    }

    public static void main(String[] args) {
        List<Product> catalog = Arrays.asList(
            new Product("Mouse",   799,   true),
            new Product("Monitor", 18999, false),
            new Product("USB Hub", 499,   true)
        );
        Product best = findMostExpensiveInStock(catalog);
        System.out.println("Most expensive in-stock: " + best.name + " ₹" + best.price);

        try {
            findMostExpensiveInStock(new ArrayList<>());
        } catch (ProductNotFoundException e) {
            System.out.println("ProductNotFoundException: " + e.getMessage());
        }
    }
}

