import java.util.*;
class Region       { String code; Region(String c) { code=c; } }
class Plan         { Region region; Plan(Region r) { region=r; } }
class Subscription { Plan plan; Subscription(Plan p) { plan=p; } }
class Customer     { Subscription sub; Customer(Subscription s) { sub=s; } 
    Subscription getSubscription() { return sub; }
}
public class App {
    static String getRegionCode(Customer customer) {
        return Optional.ofNullable(customer)
            .map(Customer::getSubscription)
            .map(s -> s.plan)
            .map(p -> p.region)
            .map(r -> r.code)
            .orElse("GLOBAL");
    }

    public static void main(String[] args) {
        Customer c1 = new Customer(
            new Subscription(new Plan(new Region("IN-HYD"))));
        Customer c2 = new Customer(null);  // no subscription

        System.out.println(getRegionCode(c1));
        System.out.println(getRegionCode(c2));
        System.out.println(getRegionCode(null));
    }
}

import java.util.*;
class UserNotFoundException extends RuntimeException {
    UserNotFoundException(String m) { super(m); }
}
class AccountSuspendedException extends RuntimeException {
    AccountSuspendedException(String m) { super(m); }
}
class User {
    int id; String name, dept; boolean active;
    User(int i, String n, String d, boolean a) { id=i; name=n; dept=d; active=a; }
}
class UserRepository {
    private Map<Integer, User> store = new HashMap<>();
    void save(User u) { store.put(u.id, u); }
    Optional<User> findById(int id) { return Optional.ofNullable(store.get(id)); }
}
class UserService {
    private UserRepository repo;
    UserService(UserRepository r) { repo=r; }

    String greet(int id) {
        User u = repo.findById(id)
            .orElseThrow(() -> new UserNotFoundException("User not found: id=" + id));
        if (!u.active) throw new AccountSuspendedException("Account suspended: " + u.name);
        return "Welcome " + u.name + " (" + u.dept + ")";
    }
}
public class App {
    static String handle(UserService svc, int id) {
        try {
            return "200 " + svc.greet(id);
        } catch (UserNotFoundException e) {
            return "404 " + e.getMessage();
        } catch (AccountSuspendedException e) {
            return "403 " + e.getMessage();
        }
    }
    public static void main(String[] args) {
        UserRepository repo = new UserRepository();
        repo.save(new User(1, "Aisha", "Engineering", true));
        repo.save(new User(2, "Raj",   "Sales",        false));
        UserService svc = new UserService(repo);

        System.out.println("GET /users/1: "  + handle(svc, 1));
        System.out.println("GET /users/99: " + handle(svc, 99));
        System.out.println("GET /users/2: "  + handle(svc, 2));
    }
}

