import java.util.*;
import java.util.stream.*;
class Product {
    String id, name, category; double price;
    Product(String i, String n, String c, double p) { id=i; name=n; category=c; price=p; }
    String getId() { return id; }
    String getName() { return name; }
    String getCategory() { return category; }
    double getPrice() { return price; }
}
public class App {
    static Optional<Product> findCheapestByCategory(List<Product> catalog, String cat) {
        return catalog.stream()
            .filter(p -> p.getCategory().equalsIgnoreCase(cat))
            .min(Comparator.comparingDouble(Product::getPrice));
    }

    static Map<String, String> getCategoryReport(List<Product> catalog) {
        return catalog.stream()
            .collect(Collectors.groupingBy(Product::getCategory,
                Collectors.collectingAndThen(
                    Collectors.toList(),
                    list -> {
                        double min = list.stream().mapToDouble(Product::getPrice).min().orElse(0);
                        double max = list.stream().mapToDouble(Product::getPrice).max().orElse(0);
                        return "₹" + min + "-₹" + max;
                    }
                )
            ));
    }

    static String findAndTransform(List<Product> catalog, String id) {
        return catalog.stream()
            .filter(p -> p.getId().equals(id))
            .findFirst()
            .map(Product::getName)
            .map(String::toUpperCase)
            .filter(s -> s.length() >= 5)
            .orElse("SHORT_ID");
    }

    static String allPricesForCategory(List<Product> catalog, String cat) {
        return catalog.stream()
            .filter(p -> p.getCategory().equalsIgnoreCase(cat))
            .sorted(Comparator.comparingDouble(Product::getPrice))
            .map(p -> "₹" + p.getPrice())
            .collect(Collectors.joining(", "));
    }

    public static void main(String[] args) {
        List<Product> catalog = Arrays.asList(
            new Product("P01", "Mouse",    "Electronics", 799),
            new Product("P02", "Keyboard", "Electronics", 1999),
            new Product("P03", "Java Book","Books",        649),
            new Product("P04", "Design Patterns", "Books", 899)
        );

        findCheapestByCategory(catalog, "Electronics")
            .ifPresent(p -> System.out.println("Cheapest Electronics: " + p.getName() + " ₹" + p.getPrice()));
        findCheapestByCategory(catalog, "Books")
            .ifPresent(p -> System.out.println("Cheapest Books: " + p.getName() + " ₹" + p.getPrice()));

        System.out.println("Category report: " + new TreeMap<>(getCategoryReport(catalog)));

        System.out.println("Transformed ID P01: " + findAndTransform(catalog, "P01"));
        System.out.println("Transformed ID P99: " + findAndTransform(catalog, "P99"));

        System.out.println("Electronics prices: " + allPricesForCategory(catalog, "Electronics"));
    }
}
